const body = $input.first().json.body;
const topicId = body.topic_id;
const action = body.action || 'publish_now';
const scheduleTime = body.schedule_time || null;

return [{ json: { topicId, action, scheduleTime } }];

const body = $input.first().json.body;
const topicId = body.topic_id;
const feedback = body.feedback || '';
const rollbackStage = body.rollback_stage || 'assembly';

// Determine which fields to reset based on rollback stage
let resetFields = { video_review_status: 'rejected', video_review_feedback: feedback };

if (rollbackStage === 'assembly') {
  resetFields.status = 'assembly';
  resetFields.assembly_status = 'pending';
} else if (rollbackStage === 'visuals') {
  resetFields.status = 'images';
  resetFields.images_progress = 'pending';
  resetFields.i2v_progress = 'pending';
  resetFields.t2v_progress = 'pending';
  resetFields.assembly_status = 'pending';
} else if (rollbackStage === 'full') {
  resetFields.status = 'audio';
  resetFields.audio_progress = 'pending';
  resetFields.images_progress = 'pending';
  resetFields.i2v_progress = 'pending';
  resetFields.t2v_progress = 'pending';
  resetFields.assembly_status = 'pending';
}

return [{ json: { topicId, feedback, rollbackStage, resetFields } }];

const body = $input.first().json.body;
const topicIds = body.topic_ids || [];

// Return each topic_id as a separate item for SplitInBatches processing
return topicIds.map(id => ({ json: { topic_id: id, total: topicIds.length } }));

const body = $input.first().json.body;
const topicId = body.topic_id;
const fields = {};

// Only include fields that are present in the request
if (body.seo_title !== undefined) fields.seo_title = body.seo_title;
if (body.description !== undefined) {
  fields.script_metadata = { ...(fields.script_metadata || {}), description: body.description };
}
if (body.tags !== undefined) {
  fields.script_metadata = { ...(fields.script_metadata || {}), tags: body.tags };
}
if (body.chapters !== undefined) {
  fields.script_metadata = { ...(fields.script_metadata || {}), chapters: body.chapters };
}
if (body.playlist_group !== undefined) fields.playlist_group = body.playlist_group;
if (body.thumbnail_prompt !== undefined) {
  fields.script_metadata = { ...(fields.script_metadata || {}), thumbnail_prompt: body.thumbnail_prompt };
}

return [{ json: { topicId, fields } }];

const response = $input.first().json;
const taskId = response.data?.task_id || response.task_id;
if (!taskId) throw new Error('No task_id in Kie.ai response');
return [{ json: { taskId } }];

const result = $input.first().json;
const status = result.data?.status || result.status;

if (status === 'completed' || status === 'succeed') {
  const imageUrl = result.data?.output?.image_urls?.[0] || result.data?.images?.[0]?.url || '';
  return [{ json: { done: true, imageUrl } }];
}

if (status === 'failed') {
  throw new Error('Thumbnail generation failed');
}

// Still processing
return [{ json: { done: false } }];

